<?php
declare(strict_types=1);require dirname(__DIR__).'/bootstrap.php';use VP3\Installation\InstallationJobService;use VP3\Hosting\HostingAccountService;$admin=vp3_require_admin_permission('hosting.view');$id=(int)vp3_input('id');
if(vp3_method()==='POST'){vp3_require_admin_permission('hosting.manage');vp3_verify_csrf();$action=vp3_input('action');if($action==='create'&&!$id){try{$id=(new HostingAccountService(vp3_db()))->create(['customer_id'=>(int)vp3_input('customer_id'),'product_id'=>(int)vp3_input('product_id'),'plan_id'=>(int)vp3_input('plan_id'),'license_id'=>(int)vp3_input('license_id'),'order_id'=>(int)vp3_input('order_id'),'subdomain'=>vp3_input('subdomain'),'custom_domain'=>vp3_input('custom_domain'),'environment'=>vp3_input('environment'),'provider'=>vp3_input('provider')]);vp3_redirect('admin/hosting-account.php?id='.$id);}catch(RuntimeException $e){vp3_flash('error','Hosting account could not be created: '.$e->getMessage());vp3_redirect('admin/hosting-account.php');}}if($id&&$action==='queue'){$svc=new InstallationJobService(vp3_db());$svc->queue($id,vp3_input('version')?:null);vp3_audit('admin',(int)$admin['id'],'installation.queued','hosting_account',(string)$id);}elseif($id&&in_array($action,['pending','active','suspended','cancelled'],true)){vp3_db()->prepare('UPDATE hosting_accounts SET hosting_status=?,updated_at=NOW() WHERE id=?')->execute([$action,$id]);vp3_audit('admin',(int)$admin['id'],'hosting.status_updated','hosting_account',(string)$id,['status'=>$action]);}vp3_redirect('admin/hosting-account.php?id='.$id);}
if(!$id){$customers=vp3_db()->query("SELECT id,name,email FROM customers WHERE status='active' ORDER BY name")->fetchAll();$products=vp3_db()->query("SELECT id,name FROM products WHERE status='active' AND hosted_enabled=1 ORDER BY name")->fetchAll();$plans=vp3_db()->query("SELECT id,name FROM product_plans WHERE status='active' AND hosting_type IN ('vp3_hosted','enterprise') ORDER BY name")->fetchAll();$licenses=vp3_db()->query("SELECT l.id,l.license_key_prefix,c.name customer_name,p.name product_name FROM licenses l JOIN customers c ON c.id=l.customer_id JOIN products p ON p.id=l.product_id WHERE l.status IN ('active','development') ORDER BY l.id DESC")->fetchAll();$orders=vp3_db()->query("SELECT o.id,o.order_number,c.name customer_name FROM orders o JOIN customers c ON c.id=o.customer_id WHERE o.payment_status='paid' ORDER BY o.id DESC")->fetchAll();$pageTitle='New Hosting Account';require VP3_ROOT.'/includes/admin-header.php';?><h1>Create hosting account</h1><form class="card" method="post"><?=vp3_csrf_field()?><input type="hidden" name="action" value="create"><div class="grid two"><div class="field"><label>Customer</label><select name="customer_id"><?php foreach($customers as $x):?><option value="<?=(int)$x['id']?>"><?=vp3_e($x['name'].' · '.$x['email'])?></option><?php endforeach;?></select></div><div class="field"><label>Product</label><select name="product_id"><?php foreach($products as $x):?><option value="<?=(int)$x['id']?>"><?=vp3_e($x['name'])?></option><?php endforeach;?></select></div><div class="field"><label>Plan</label><select name="plan_id"><option value="0">No plan</option><?php foreach($plans as $x):?><option value="<?=(int)$x['id']?>"><?=vp3_e($x['name'])?></option><?php endforeach;?></select></div><div class="field"><label>License</label><select name="license_id"><option value="0">No license</option><?php foreach($licenses as $x):?><option value="<?=(int)$x['id']?>"><?=vp3_e($x['customer_name'].' · '.$x['product_name'].' · '.$x['license_key_prefix'])?>…</option><?php endforeach;?></select></div><div class="field"><label>Paid order</label><select name="order_id"><option value="0">Development / manual</option><?php foreach($orders as $x):?><option value="<?=(int)$x['id']?>"><?=vp3_e($x['order_number'].' · '.$x['customer_name'])?></option><?php endforeach;?></select></div><div class="field"><label>Subdomain</label><input name="subdomain" pattern="[a-z0-9][a-z0-9-]{1,61}[a-z0-9]" required></div><div class="field"><label>Custom domain</label><input name="custom_domain"></div><div class="field"><label>Environment</label><select name="environment"><option>production</option><option>staging</option><option>development</option></select></div><div class="field"><label>Provider</label><select name="provider"><option>local_simulator</option><option>manual</option></select></div></div><button class="button">Create hosting account</button></form><?php require VP3_ROOT.'/includes/admin-footer.php';exit;}
$s=vp3_db()->prepare('SELECT h.*,c.name customer_name,p.name product_name,l.license_key_prefix FROM hosting_accounts h JOIN customers c ON c.id=h.customer_id JOIN products p ON p.id=h.product_id LEFT JOIN licenses l ON l.id=h.license_id WHERE h.id=?');$s->execute([$id]);$row=$s->fetch();if(!is_array($row)){http_response_code(404);exit('Hosting account not found.');}$jobs=vp3_db()->prepare('SELECT * FROM installation_jobs WHERE hosting_account_id=? ORDER BY id DESC');$jobs->execute([$id]);$pageTitle='Hosting Account';require VP3_ROOT.'/includes/admin-header.php';?><h1><?=vp3_e($row['subdomain'].'.'.vp3_config('hosting.base_domain'))?></h1><div class="grid two"><article class="card"><p>Customer: <?=vp3_e($row['customer_name'])?></p><p>Product: <?=vp3_e($row['product_name'])?></p><p>Environment: <?=vp3_e($row['environment'])?></p><p>Provider: <?=vp3_e($row['provider'])?></p><p>License: <?=vp3_e($row['license_key_prefix'])?>…</p><p>Installed version: <?=vp3_e($row['installed_version']?:'None')?></p></article><form class="card" method="post"><?=vp3_csrf_field()?><div class="field"><label>Hosting status</label><select name="action"><?php foreach(['pending','active','suspended','cancelled'] as $st):?><option <?=$row['hosting_status']===$st?'selected':''?>><?=$st?></option><?php endforeach;?></select></div><button class="button small">Update</button></form></div><form class="card" method="post"><?=vp3_csrf_field()?><input type="hidden" name="action" value="queue"><div class="field"><label>Requested version (optional)</label><input name="version"></div><button class="button">Queue installation job</button></form><h2>Installation history</h2><div class="table-wrap"><table class="table"><thead><tr><th>Job</th><th>Status</th><th>Step</th><th>Progress</th><th>Failure</th></tr></thead><tbody><?php foreach($jobs->fetchAll() as $j):?><tr><td><?=vp3_e($j['job_uuid'])?></td><td><?=vp3_e($j['job_status'])?></td><td><?=vp3_e($j['current_step'])?></td><td><?=(int)$j['progress_percent']?>%</td><td><?=vp3_e($j['failure_message'])?></td></tr><?php endforeach;?></tbody></table></div><?php require VP3_ROOT.'/includes/admin-footer.php';?>
